using System.Collections.Immutable;
using System.Runtime.CompilerServices;
using System.Text;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.Text;

[assembly: InternalsVisibleTo("sqlx-cs-pg-internal-generator-test")]
namespace Sqlx.Postgres.Generator.Result;

[Generator]
internal sealed class PgDataRowDecoderGenerator : IIncrementalGenerator
{
    private const string GeneratePgDecodeMethodAttribute =
        """
        // <auto-generated/>
        #nullable enable

        namespace Sqlx.Postgres.Generator.Result;
        
        [global::System.AttributeUsage(validOn: global::System.AttributeTargets.Method)]
        public sealed class GeneratePgDecodeMethodAttribute : global::System.Attribute
        {
            public required System.Type Decoder { get; init; }
        }
        """;
    
    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        context.RegisterPostInitializationOutput(static ctx =>
        {
            ctx.AddSource(
                "GeneratePgDecodeMethodAttribute.g.cs",
                SourceText.From(GeneratePgDecodeMethodAttribute, Encoding.UTF8));
        });

        var typesToGenerate = context.SyntaxProvider
            .ForAttributeWithMetadataName(
                "Sqlx.Postgres.Generator.Result.GeneratePgDecodeMethodAttribute",
                predicate: static (_, _) => true,
                transform: static (ctx, _) =>
                    GetTargetForGeneration(ctx.SemanticModel, ctx.TargetNode))
            .Where(static m => m is not null);

        context.RegisterSourceOutput(
            typesToGenerate.Collect(),
            static (spc, source) => Execute(source, spc));
    }
    
    private static DecodeMethodToGenerate? GetTargetForGeneration(
        SemanticModel semanticModel,
        SyntaxNode syntax)
    {
        return semanticModel.GetDeclaredSymbol(syntax) is not IMethodSymbol methodSymbol
            ? null
            : new DecodeMethodToGenerate(methodSymbol);
    }

    private static void Execute(
        ImmutableArray<DecodeMethodToGenerate?> methodsToGenerate,
        SourceProductionContext context)
    {
        if (methodsToGenerate.IsDefaultOrEmpty) return;

        StringBuilder builder = new(
            """
            // <auto-generated/>
            #nullable enable
            
            using Sqlx.Core.Result;
            using Sqlx.Postgres.Exceptions;
            using Sqlx.Postgres.Type;
            
            namespace Sqlx.Postgres.Result;
            
            public static partial class DataRowExtensions
            {
            """);
        foreach (DecodeMethodToGenerate? methodToGenerate in methodsToGenerate)
        {
            context.CancellationToken.ThrowIfCancellationRequested();
            if (methodToGenerate is null)
            {
                continue;
            }

            if (!methodToGenerate.Validate(context))
            {
                continue;
            }
            
            var sourceCode = GenerateDecodeMethod(methodToGenerate);
            builder.AppendLine();
            foreach (var line in sourceCode.Split('\n'))
            {
                builder.Append("    ");
                builder.AppendLine(line);
            }
        }

        builder.Append('}');
        builder.AppendLine();
        
        context.AddSource(
            "DecodeMethods.g.cs",
            SourceText.From(builder.ToString(), Encoding.UTF8));
    }

    private static string GenerateDecodeMethod(DecodeMethodToGenerate decodeMethodToGenerate)
    {
        var resultTypeName = decodeMethodToGenerate.ReturnType.ToDisplayString();
        string decoderTypeName;
        if (decodeMethodToGenerate.IsArrayReturn)
        {
            ITypeSymbol resultTypeElement = SourceGenerationHelper.NotNullType(
                ((IArrayTypeSymbol)decodeMethodToGenerate.ReturnType).ElementType);
            var resultTypeElementName = resultTypeElement.ToDisplayString();
            var tempDecoderTypeName = decodeMethodToGenerate.DecoderType.ToDisplayString();
            decoderTypeName = resultTypeElement.IsValueType
                ? $"PgArrayTypeStruct<{resultTypeElementName}, {tempDecoderTypeName}>"
                : $"PgArrayTypeClass<{resultTypeElementName}, {tempDecoderTypeName}>";
        }
        else
        {
            decoderTypeName = decodeMethodToGenerate.DecoderType.ToDisplayString();
        }
        
        var indexerName = decodeMethodToGenerate.IndexerParameterName;
        var indexerIsString = decodeMethodToGenerate.IndexerParameterType.ToDisplayString() is "string";
        var signature = $"public static partial {resultTypeName}{(decodeMethodToGenerate.IsReturnNullable ? '?' : string.Empty)} {decodeMethodToGenerate.Name}(this IDataRow dataRow, {decodeMethodToGenerate.IndexerParameterType.ToDisplayString()} {indexerName})";
        if (decodeMethodToGenerate.IsReturnNullable)
        {
            return indexerIsString
                ? $$"""
                    {{signature}}
                    {
                        int index = dataRow.IndexOf({{indexerName}});
                        if (dataRow.IsNull(index))
                        {
                            return null;
                        }
                        return PgException.CheckIfIs<IDataRow, IPgDataRow>(dataRow)
                            .GetPgNotNull<{{resultTypeName}}, {{decoderTypeName}}>(index);
                    }
                    """
                : $$"""
                    {{signature}}
                    {
                        if (dataRow.IsNull({{indexerName}}))
                        {
                            return null;
                        }
                        return PgException.CheckIfIs<IDataRow, IPgDataRow>(dataRow)
                            .GetPgNotNull<{{resultTypeName}}, {{decoderTypeName}}>({{indexerName}});
                    }
                    """;
        }

        return indexerIsString
            ? $"{signature} =>\n    PgException.CheckIfIs<IDataRow, IPgDataRow>(dataRow)\n        .GetPgNotNull<{resultTypeName}, {decoderTypeName}>(dataRow.IndexOf({indexerName}));"
            : $"{signature} =>\n    PgException.CheckIfIs<IDataRow, IPgDataRow>(dataRow)\n        .GetPgNotNull<{resultTypeName}, {decoderTypeName}>({indexerName});";
    }
}
